      "path": "src/cli/specify.ts",
      "content": "#!/usr/bin/env node
import { Command } from 'commander';
import { specify } from '../specify.js';

const program = new Command()
  .name('night-shift specify')
  .description('Generate spec bundle from GitHub ticket')
  .argument('<ticket>', 'Ticket URL or ID')
  .option('--strict', 'Exit non-zero if any open questions remain')
  .action(async (ticket, cmd) => {
    try {
      const result = await specify({ ticket });
      console.log(JSON.stringify(result, null, 2));
      if (cmd.strict && result.openQuestions?.length > 0) {
        console.error(`${result.openQuestions.length} open questions remain.`);
        process.exit(2);
      }
    } catch (error) {
      console.error(error);
      process.exit(1);
    }
  });

(async () => {
  await program.parseAsync(process.argv);
  process.exit(0);
})();"
