      "path": "src/cli/specify.test.ts",
      "content": "import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import process from 'process';
import { specify } from '../specify.js';

const mockSpecify = vi.mocked(specify);

vi.mock('../specify.js');

describe('night-shift specify CLI', () => {
  let consoleLogSpy: ReturnType<typeof vi.spyOn<typeof console, 'log'>>;
  let consoleErrorSpy: ReturnType<typeof vi.spyOn<typeof console, 'error'>>;
  let exitSpy: ReturnType<typeof vi.spyOn<typeof process, 'exit'>>;
  const oldArgv = process.argv;

  const runCLI = async (args: string[]) => {
    process.argv = ['node', 'night-shift', 'specify', ...args];
    await import('./specify');
  };

  beforeEach(() => {
    consoleLogSpy = vi.spyOn(console, 'log').mockImplementation(() => {});
    consoleErrorSpy = vi.spyOn(console, 'error').mockImplementation(() => {});
    exitSpy = vi.spyOn(process, 'exit').mockImplementation(() => {});
    mockSpecify.mockClear();
  });

  afterEach(() => {
    process.argv = oldArgv;
    vi.restoreAllMocks();
  });

  it('exits 2 with --strict and open questions', async () => {
    mockSpecify.mockResolvedValue({ openQuestions: ['question'] });
    await runCLI(['--strict', 'https://example.com/ticket']);
    expect(mockSpecify).toHaveBeenCalledWith({ ticket: 'https://example.com/ticket' });
    expect(exitSpy).toHaveBeenCalledWith(2);
  });

  it('exits 0 with --strict but empty openQuestions', async () => {
    mockSpecify.mockResolvedValue({ openQuestions: [] });
    await runCLI(['--strict', 'https://example.com/ticket']);
    expect(exitSpy).toHaveBeenCalledWith(0);
  });

  it('exits 0 without --strict even with open questions', async () => {
    mockSpecify.mockResolvedValue({ openQuestions: ['question'] });
    await runCLI(['https://example.com/ticket']);
    expect(exitSpy).toHaveBeenCalledWith(0);
  });

  it('--help lists the --strict flag', async () => {
    process.argv = ['node', 'night-shift', 'specify', '--help'];
    await import('./specify');
    const helpText = [...consoleLogSpy.mock.calls, ...consoleErrorSpy.mock.calls]
      .map((call) => (call as unknown[])[0])
      .join('\n');
    expect(helpText).toContain('--strict');
  });
});"
    }
